window.Motion = window.Motion || {};
(function () {
    function spring(stiffness, damping, mass) {
        return {
            type: "spring",
            stiffness: Number(stiffness) || 200,
            damping: Number(damping) || 24,
            mass: Number(mass) || 1,
        };
    }

    function animate(target, keyframes, opts) {
        opts = opts || {};
        var duration = Number(opts.duration || 0.2);
        var useMs = duration <= 1 ? duration * 1000 : duration;
        if (!target || !target.style) {
            return {
                finished: Promise.resolve(),
                stop: function () {},
            };
        }

        var frames = keyframes && keyframes.transform && Array.isArray(keyframes.transform)
            ? keyframes.transform
            : [1, 1, 1];
        var fromScale = Number(frames[0]) || 1;
        var toScale = Number(frames[frames.length - 1]) || 1;
        var midScale = Number(frames.length > 1 ? frames[1] : toScale) || toScale;

        var start = Date.now();
        var stopped = false;
        var rafId = 0;
        var resolveFn;
        var finished = new Promise(function (resolve) {
            resolveFn = resolve;
        });

        function clamp(value) {
            return Math.max(0, Math.min(1, value));
        }

        function ease(t) {
            return t < 0.5
                ? 4 * t * t * t
                : 1 - Math.pow(-2 * t + 2, 3) / 2;
        }

        function step() {
            if (stopped) {
                return;
            }
            var elapsed = Date.now() - start;
            var progress = clamp(elapsed / useMs);
            var t = ease(progress);

            var scale;
            if (progress < 0.5) {
                scale = fromScale + (midScale - fromScale) * (t * 2);
            } else {
                scale = midScale + (toScale - midScale) * ((t - 0.5) * 2);
            }
            target.style.transform = "scale(" + scale + ")";

            if (progress < 1) {
                rafId = window.requestAnimationFrame(step);
                return;
            }
            target.style.transform = "scale(" + toScale + ")";
            resolveFn();
        }

        rafId = window.requestAnimationFrame(step);

        return {
            finished: finished,
            stop: function () {
                if (stopped) {
                    return;
                }
                stopped = true;
                if (rafId) {
                    window.cancelAnimationFrame(rafId);
                }
                resolveFn();
            },
        };
    }

    window.Motion.animate = animate;
    window.Motion.spring = spring;
})();
